// AdminMutation returns AdminMutationResolver implementation.
func (r *Resolver) AdminMutation() AdminMutationResolver { return &adminMutationResolver{r} }

// AdminQuery returns AdminQueryResolver implementation.
func (r *Resolver) AdminQuery() AdminQueryResolver { return &adminQueryResolver{r} }

type (
	adminMutationResolver struct{ *Resolver }
	adminQueryResolver    struct{ *Resolver }
)

func mapAdminUser(user *domain.AdminUser) *model.AdminUser {
	if user == nil {
		return nil
	}

	return &model.AdminUser{
		ID:                    user.ID,
		Name:                  toOptionalAdminProfileName(user.Name),
		Username:              toOptionalAdminUsername(user.Username),
		AvatarURL:             toOptionalAdminAvatarURL(user.AvatarURL),
		Email:                 user.Email,
		PendingEmail:          toOptionalAdminEmail(user.PendingEmail),
		PendingEmailExpiresAt: user.PendingEmailExpiresAt,
		GoogleLinked:          strings.TrimSpace(user.GoogleSubject) != "",
		GoogleEmail:           toOptionalAdminEmail(user.GoogleEmail),
		GoogleLinkedAt:        user.GoogleLinkedAt,
		Roles:                 append([]string{}, user.Roles...),
	}
}

func toOptionalAdminProfileName(value string) *string {
	trimmed := strings.TrimSpace(value)
	if trimmed == "" {
		return nil
	}

	return &trimmed
}

func toOptionalAdminUsername(value string) *string {
	trimmed := strings.TrimSpace(value)
	if trimmed == "" {
		return nil
	}

	return &trimmed
}

func toOptionalAdminEmail(value string) *string {
	trimmed := strings.TrimSpace(strings.ToLower(value))
	if trimmed == "" {
		return nil
	}

	return &trimmed
}

func toOptionalAdminAvatarURL(value string) *string {
	trimmed := strings.TrimSpace(value)
	if trimmed == "" {
		return nil
	}

	return &trimmed
}

