func mapAdminContentTopicIDs(values []string) []string {
	if len(values) == 0 {
		return []string{}
	}

	ids := make([]string, 0, len(values))
	for _, value := range values {
		trimmed := strings.TrimSpace(value)
		if trimmed == "" {
			continue
		}
		ids = append(ids, trimmed)
	}

	return ids
}

func stringPointerValue(value *string) string {
	if value == nil {
		return ""
	}
	return *value
}

func toOptionalTrimmedInputString(value *string) *string {
	if value == nil {
		return nil
	}
	trimmed := strings.TrimSpace(*value)
	return &trimmed
}

func toOptionalAdminString(value string) *string {
	trimmed := strings.TrimSpace(value)
	if trimmed == "" {
		return nil
	}

	return &trimmed
}

func toOptionalAdminTime(value time.Time) *time.Time {
	if value.IsZero() {
		return nil
	}

	normalized := value.UTC()
	return &normalized
}

func toOptionalAdminTimePointer(value *time.Time) *time.Time {
	if value == nil {
		return nil
	}
	return toOptionalAdminTime(*value)
}

